@timer
def leetcode():

        n= len(nums)
        if n==1:
            return nums[0]
            # print( nums[0])
        for a in range(n):
            cnt =1
            for i in nums[a+1:]:
                if nums[a] ==i:
                    cnt +=1
                if cnt> n/2:
                    # print(i)
                    return i
                    break
            if cnt> n/2:
                break

